import React from 'react';

const ResultPage = ({ result, teamInfo }) => {
  const { score, totalQuestions, timeTaken } = result;

  const formatTime = (microseconds) => {
    const seconds = Math.floor(microseconds / 1_000_000);
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}m ${remainingSeconds}s`;
  };

  const formatMicroseconds = (microseconds) => {
    return microseconds.toLocaleString();
  };

  const percentage = Math.round((score / totalQuestions) * 100);

  const getMessage = () => {
    if (percentage >= 80) return 'Excellent work!';
    if (percentage >= 60) return 'Good job!';
    if (percentage >= 40) return 'Nice try!';
    return 'Better luck next time!';
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: '#ffffff'
    }}>
      <div style={{
        width: '100%',
        maxWidth: '500px',
        padding: '40px',
        textAlign: 'center'
      }}>
        <h1 style={{ 
          fontSize: '36px', 
          marginBottom: '10px', 
          color: '#1a202c',
          fontWeight: '700'
        }}>
          Quiz Complete!
        </h1>

        <p style={{ 
          color: '#4a5568', 
          marginBottom: '30px', 
          fontSize: '18px',
          fontWeight: '500'
        }}>
          {teamInfo.teamName}
        </p>

        <div style={{ 
          backgroundColor: '#f8f9fa',
          padding: '30px',
          borderRadius: '12px',
          marginBottom: '20px',
          border: '1px solid #e9ecef'
        }}>
          <div style={{ 
            fontSize: '64px', 
            fontWeight: '700', 
            color: '#1a202c',
            marginBottom: '10px'
          }}>
            {score}/{totalQuestions}
          </div>

          <div style={{ 
            fontSize: '24px', 
            color: '#2d3748',
            marginBottom: '15px',
            fontWeight: '600'
          }}>
            {percentage}%
          </div>

          <div style={{ 
            fontSize: '18px', 
            color: '#4a5568',
            marginBottom: '20px'
          }}>
            {getMessage()}
          </div>

          <div style={{ 
            fontSize: '14px', 
            color: '#718096',
            padding: '15px',
            backgroundColor: '#ffffff',
            borderRadius: '8px',
            border: '1px solid #e9ecef'
          }}>
            <div>Time taken: {formatTime(timeTaken)}</div>
            <div style={{ fontSize: '12px', marginTop: '5px', color: '#adb5bd' }}>
              ({formatMicroseconds(timeTaken)} microseconds)
            </div>
          </div>
        </div>

        <p style={{ color: '#6c757d', fontSize: '14px' }}>
          Thank you for participating!
        </p>
      </div>
    </div>
  );
};

export default ResultPage;
